**Example (JavaScript):**
```javascript
// JavaScript (Duck Typing)
const dog = {
  speak() { return "Woof"; }
};

const cat = {
  speak() { return "Meow"; }
};

// We don't care if they are 'Dog' or 'Cat' classes.
// We only care that they have a 'speak' method.
function makeAnimalSpeak(animal) {
  return animal.speak(); 
}

**Example:**
```typescript
// Define an interface (The "Duck" definition)
interface Duck {
  quack(): void;
  swim(): void;
}

// A function expecting a Duck
function feedDuck(duck: Duck) {
  duck.quack();
  duck.swim();
}

// Object A: Explicitly implements the interface
const realDuck: Duck = {
  quack() { console.log("Quack"); },
  swim() { console.log("Swimming"); }
};

// Object B: Does NOT implement the interface explicitly,
// but has the same structure (Duck Typing in action!)
const rubberDuck = {
  quack() { console.log("Squeak"); },
  swim() { console.log("Floating"); }
};

// TypeScript accepts rubberDuck because it "looks like a duck"
feedDuck(realDuck);   // ✅ Works
feedDuck(rubberDuck); // ✅ Works! (Structural compatibility)

// Object C: Missing a method
const brokenDuck = {
  quack() { console.log("Quack"); }
  // Missing 'swim'
};

// TypeScript rejects this at compile time
feedDuck(brokenDuck); // ❌ Error: Property 'swim' is missing.
```

